// Konsert planlaşdırma funksiyası
function setupConcert(task, callback) {
  console.log(`Tapşırıq yerinə yetirilir: ${task}`);
  setTimeout(() => {
    console.log(`${task} tamamlandı!`);
    callback();
  }, 2000);
}

// Geri çağırış funksiyaları
function callMusicians() {
  console.log("Musiqiçilər çağırıldı.");
}

function sellTickets() {
  console.log("Biletlər satışa çıxarıldı.");
}

// Geri çağırış ilə istifadə
setupConcert("Səhnə qurulur", callMusicians);
// nəticə:
// Tapşırıq yerinə yetirilir: Səhnə qurulur
// (2 saniyə sonra) Səhnə qurulur tamamlandı!
// Musiqiçilər çağırıldı.

// Zəncirlənmiş geri çağırış
setupConcert("Səhnə qurulur", () => {
  console.log("Səhnə hazırdır!");
  setupConcert("Musiqiçilər hazırlanır", sellTickets);
});
// nəticə:
// Tapşırıq yerinə yetirilir: Səhnə qurulur
// (2 saniyə sonra) Səhnə qurulur tamamlandı!
// Səhnə hazırdır!
// Tapşırıq yerinə yetirilir: Musiqiçilər hazırlanır
// (2 saniyə sonra) Musiqiçilər hazırlanır tamamlandı!
// Biletlər satışa çıxarıldı.

// Callback Hell nümunəsi
setupConcert("Səhnə qurulur", () => {
  console.log("Səhnə hazırdır!");
  setupConcert("Musiqiçilər hazırlanır", () => {
    console.log("Musiqiçilər hazırdır!");
    setupConcert("Biletlər satılır", () => {
      console.log("Konsert başlaya bilər!");
    });
  });
});

// Səhv idarəetmə ilə geri çağırış
function setupConcertWithError(task, callback) {
  console.log(`Tapşırıq: ${task}`);
  setTimeout(() => {
    if (task === "Səhnə qurulur" && Math.random() > 0.7) {
      callback(new Error("Səhnə qurmaq alınmadı!"));
    } else {
      callback(null, `${task} tamamlandı!`);
    }
  }, 2000);
}

setupConcertWithError("Səhnə qurulur", (err, result) => {
  if (err) {
    console.log("Səhv: ", err.message);
    return;
  }
  console.log(result);
});

