// Concert planning function
function setupConcert(task, callback) {
  console.log(`Task started: ${task}`);
  setTimeout(() => {
    console.log(`${task} completed!`);
    callback();
  }, 2000);
}

// Callback functions
function callMusicians() {
  console.log("Musicians called.");
}

function sellTickets() {
  console.log("Tickets put on sale.");
}

// Using a callback
setupConcert("Set up stage", callMusicians);
// Output:
// Task started: Set up stage
// (2 seconds later) Set up stage completed!
// Musicians called.

// Chained callbacks
setupConcert("Set up stage", () => {
  console.log("Stage is ready!");
  setupConcert("Prepare musicians", sellTickets);
});
// Output:
// Task started: Set up stage
// (2 seconds later) Set up stage completed!
// Stage is ready!
// Task started: Prepare musicians
// (2 seconds later) Prepare musicians completed!
// Tickets put on sale.

// Callback Hell example
setupConcert("Set up stage", () => {
  console.log("Stage is ready!");
  setupConcert("Prepare musicians", () => {
    console.log("Musicians ready!");
    setupConcert("Sell tickets", () => {
      console.log("Concert can start!");
    });
  });
});

// Error handling with callbacks
function setupConcertWithError(task, callback) {
  console.log(`Task: ${task}`);
  setTimeout(() => {
    if (task === "Set up stage" && Math.random() > 0.7) {
      callback(new Error("Stage setup failed!"));
    } else {
      callback(null, `${task} completed!`);
    }
  }, 2000);
}

setupConcertWithError("Set up stage", (err, result) => {
  if (err) {
    console.log("Error: ", err.message);
    return;
  }
  console.log(result);
});

