// Функция планирования концерта
function setupConcert(task, callback) {
  console.log(`Задача начата: ${task}`);
  setTimeout(() => {
    console.log(`${task} завершена!`);
    callback();
  }, 2000);
}

// Функции обратного вызова
function callMusicians() {
  console.log("Музыканты вызваны.");
}

function sellTickets() {
  console.log("Билеты выставлены на продажу.");
}

// Использование обратного вызова
setupConcert("Установка сцены", callMusicians);
// Вывод:
// Задача начата: Установка сцены
// (2 секунды спустя) Установка сцены завершена!
// Музыканты вызваны.

// Цепочка обратных вызовов
setupConcert("Установка сцены", () => {
  console.log("Сцена готова!");
  setupConcert("Подготовка музыкантов", sellTickets);
});
// Вывод:
// Задача начата: Установка сцены
// (2 секунды спустя) Установка сцены завершена!
// Сцена готова!
// Задача начата: Подготовка музыкантов
// (2 секунды спустя) Подготовка музыкантов завершена!
// Билеты выставлены на продажу.

// Пример Callback Hell
setupConcert("Установка сцены", () => {
  console.log("Сцена готова!");
  setupConcert("Подготовка музыкантов", () => {
    console.log("Музыканты готовы!");
    setupConcert("Продажа билетов", () => {
      console.log("Концерт может начаться!");
    });
  });
});

// Обработка ошибок с обратными вызовами
function setupConcertWithError(task, callback) {
  console.log(`Задача: ${task}`);
  setTimeout(() => {
    if (task === "Установка сцены" && Math.random() > 0.7) {
      callback(new Error("Установка сцены не удалась!"));
    } else {
      callback(null, `${task} завершена!`);
    }
  }, 2000);
}

setupConcertWithError("Установка сцены", (err, result) => {
  if (err) {
    console.log("Ошибка: ", err.message);
    return;
  }
  console.log(result);
});

